var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"처음 뵙겠습니다. 오늘부터 판도라에서 일하게 된 서가람입니다.","JPN":"はじめまして。本日からパンドラで働くことになりました、カワセ・ヒカリです。","ENG":"Hello. I'm Seo Garam, and I will be working at Pandora starting today.","TWN":"初次見面，我是從今天開始在潘朵拉工作的徐嘉蘭。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"시뮬레이션 개발 부서에 들어오기 위해, 지금까지 많은 경력을 쌓으며 노력해 왔어요.","JPN":"シミュレーション開発部署に入るために、今まで色んな経験を積んで努力してきました。","ENG":"I worked hard to build my career so that I could join the Simulation Department in Pandora.","TWN":"為了進入模擬開發部門，我一直在積累經驗並努力工作。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"모두 잘 부탁드릴게요! 열심히 하겠습니다!","JPN":"よろしくお願いします！　一生懸命頑張ります！","ENG":"I look forward to working with you all! I'll do my best!","TWN":"大家請多指教！我會努力的！"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"환영해요……. 가람 씨.","JPN":"歓迎します……ヒカリさん。","ENG":"Welcome... Garam.","TWN":"歡迎……嘉蘭。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"진보라라고 해요……. 잘 부탁해요.","JPN":"タカダ・シホです……よろしく。","ENG":"I'm Jin Bora... I look forward to working with you too.","TWN":"我叫陳寶拉……請多關照。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"와~ 같이 일하게 돼서 영광이에요!","JPN":"わ～一緒にお仕事できて光栄です！","ENG":"Wow! It's an honor to work with you!","TWN":"哇～能和你一起工作真是太榮幸了！"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"보라 씨의 명성은 예전부터 많이 들어왔답니다.","JPN":"シホさんの名声は昔から聞いています。","ENG":"I've heard a lot about you, Ms. Jin!","TWN":"久仰大名。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"카운터즈 시리즈와 시뮬레이션 개발의 권위자시잖아요?","JPN":"カウンターズシリーズとシミュレーション開発の権威者じゃないですか。","ENG":"You're an expert in the field of simulation, not to mention you were in charge of developing the Counters series!","TWN":"你可是制裁者系列和模擬開發的權威啊？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"부끄러워요…… 그렇게 띄워주면.","JPN":"恥ずかしいです……そんなにおだてられると。","ENG":"Please don't... praise me like that.","TWN":"好害羞……被你這麼誇獎。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"엇, 왜 그러세요……?","JPN":"え、どうしました……？","ENG":"Huh? Why are you looking at me like that...?","TWN":"啊，怎麼了……？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"오피스레이디Y 맞죠……? 그 란도셀.","JPN":"オフィスレディーYですよね……？　そのランドセル。","ENG":"That's Office Lady Y, right...? The randoseru?","TWN":"是上班女郎Y吧……？那個書包。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"전체적으로 쏙 닮았네요. 란도셀뿐만 아니라.","JPN":"全体的にそっくりですね。ランドセルだけじゃなくて。","ENG":"You look just like her. Not just the randoseru.","TWN":"整體上非常相似。不僅僅是書包。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"아하하, 역시 알아보셨군요? 전 스트리트 카운터의 왕팬이거든요.","JPN":"あはは、やっぱりわかってくれましたか！　私、ストリート・カウンターの大ファンなんです。","ENG":"Ah hah hah, did you notice? I'm a huge fan of Street Counter.","TWN":"哈哈哈，果然認出來了吧？我是街頭制裁者的粉絲喔。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"보라 씨라면 고증을 지키고픈 팬의 마음, 잘 아시죠?","JPN":"シホさんは原作を再現したいファンの気持ち、わかりますよね？","ENG":"I'm sure you know how important the details are to a fan, right?","TWN":"寶拉應該很了解的粉絲心情吧？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"<color=#ffd34c>……닮았네요. 제가 알던 아이와.</color>","JPN":"<color=#ffd34c>……似てますね。私の知ってる子と。</color>","ENG":"<color=#ffd34c>...You resemble someone I know.</color>","TWN":"<color=#ffd34c>……真像。和我認識的孩子。</color>"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"응? 그게 누구죠?","JPN":"え？　誰ですか？","ENG":"Hmm? Who might that be?","TWN":"嗯？那是誰？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"안내할게요…… 자리로.","JPN":"案内します……席に。","ENG":"I'll show you... to your seat.","TWN":"我來帶路……"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"개발 중인…… 저희 프로젝트도.","JPN":"開発中の……私たちのプロジェクトも。","ENG":"And the project... we are working on.","TWN":"我們開發中的……專案。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"네! 벌써부터 일할 생각에 정말 두근거리네요!","JPN":"はい！　ここで仕事ができるんだと思うとわくわくしてきます！","ENG":"Okay! I'm so excited to start work!","TWN":"是的！一想到要工作就讓我心跳加速！"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"혹시 프로젝트명이 뭔지 알 수 있을까요?","JPN":"プロジェクト名をお伺いしてもいいでしょうか？","ENG":"Can you tell me the project name?","TWN":"請問可以知道項目名稱嗎？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"카운터즈…… 레거시.","JPN":"カウンターズ……レガシー。","ENG":"Counters... Legacy.","TWN":"制裁者……的遺產。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"다들 모이셨나요? 그럼 회의 시작하도록 하겠습니다!","JPN":"皆さん集まりましたか？　では会議を始めます！","ENG":"Is everyone here? Then, I'll start the meeting!","TWN":"大家都到齊了嗎？那我們開始會議吧！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"카운터즈 레거시에는 침식체뿐만 아니라, 카운터끼리의 대인전도 디자인해 보려 합니다.","JPN":"カウンターズ・レガシーに侵食体だけじゃなく、カウンター同士の対人戦も実装しようと思います。","ENG":"For Counters Legacy, I am planning to add PvP mode where Counters can battle each other and not only the C.O.s.","TWN":"制裁者的遺產不僅會設計對抗侵蝕體的戰鬥，還會設計制裁者之間的對戰。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"카운터즈 레거시는 카운터의 모의전투 시뮬레이션을 기반으로 개발되었죠.","JPN":"カウンターズ・レガシーは、カウンターの模擬戦闘シミュレーションを基に開発されたものです。","ENG":"Counters Legacy was developed based on Counter simulation training.","TWN":"制裁者的遺產是基於制裁者的模擬戰鬥開發的。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"그렇기에 다양한 전투 경험을 쌓을 수 있게 하는 것이 중요하다고 생각해요.","JPN":"だからこそ、様々な戦闘経験を積める環境を提供することが大事だと思います。","ENG":"That's why I think it's important for them to gain a variety of combat experiences.","TWN":"因此，我認為讓他們積累各種戰鬥經驗是很重要的。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};